import React from 'react';
import FullWidthPageLayout from '@layouts/FullWidthPage';
import ContactHeroBanner from '@components/ContactHeroBanner';
import Seo from '@components/Seo';

export default function ContactPage() {
	return (
		<FullWidthPageLayout>
			<ContactHeroBanner />
		</FullWidthPageLayout>
	);
}

// export function Head() {
// 	return <Seo title="Contact Us" urlPath="/contact" />;
// }
export function Head({ location }) {
	return <Seo title="Contact Us" description="Get in touch with us for any queries and we shall be happy to respond" urlPath={'/' + location.pathname} />;
}
