import React from 'react';
import { Link } from 'gatsby';
import HorizontalPan from '@containers/HorizontalPan';
import { LinkButton } from '@components/ui/Button';
import * as styles from './footer.module.css';

export default function Footer() {
	return (
		<footer id={styles.ftr}>
			<HorizontalPan className={styles.ftrRow} panOnTouchDeviceOnly={true}>
				<div>
					<h3>Product</h3>
					<ul>
						<li>
							<Link activeClassName={styles.active} to="/about">
								About Kaagzi
							</Link>
						</li>
						<li>
							<Link activeClassName={styles.active} to="/pricing">
								Pricing
							</Link>
						</li>
						<li>
							<Link activeClassName={styles.active} to="/guide">
								Guide
							</Link>
						</li>
						<li>
							<Link activeClassName={styles.active} to="/terms-of-use">
								Terms Of Use
							</Link>
						</li>
					</ul>
				</div>
				<div>
					<h3>More</h3>
					<ul>
						<li>
							<Link activeClassName={styles.active} to="/privacy-policy">
								Privacy Policy
							</Link>
						</li>
						<li>
							<Link activeClassName={styles.active} to="/cookie-policy">
								Cookie Policy
							</Link>
						</li>
						<li>
							<Link activeClassName={styles.active} to="/frequently-asked-questions">
								FAQs
							</Link>
						</li>
						<li>
							<Link activeClassName={styles.active} to="/contact">
								Contact
							</Link>
						</li>
					</ul>
				</div>
				<ul>
					<li>
						<LinkButton variant="primary" to="/app" size="big">
							Get App
						</LinkButton>
					</li>
					<li>
						<LinkButton variant="tertiary" to="/guide" size="big">
							View Guide
						</LinkButton>
					</li>
				</ul>
			</HorizontalPan>
			<div>
				{/* <span>
					<LinkButton to="https://facebook.com" variant="tertiary" icon="facebook-square" isDark={true} />
					<LinkButton to="https://instagram.com" variant="tertiary" icon="instagram" isDark={true} />
					<LinkButton to="https://twitter.com" variant="tertiary" icon="twitter" isDark={true} />
				</span> */}
				<span>Copyright &copy; 2024, Kaagzi</span>
			</div>
		</footer>
	);
}
